const claudeResponse = $input.first().json;
const prepData = $('Preparar Datos').first().json;
const montoEsperado = prepData.montoEsperado;

// Extract text from Claude response
const textContent = claudeResponse.content?.[0]?.text || '';

let extractedData = { monto: null, nombreDestinatario: null, celularDestino: null };
try {
  const jsonMatch = textContent.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    extractedData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.error('Error parsing Claude response:', e.message, '| Raw text:', textContent);
}

const montoDetectado = parseFloat(extractedData.monto) || 0;
const nombreDetectado = (extractedData.nombreDestinatario || '').toLowerCase().trim();
const celularDetectado = String(extractedData.celularDestino || '').replace(/[^0-9]/g, '');

// Expected SINPE data
const NOMBRE_ESPERADO = 'elvis rocha';
const CELULAR_ESPERADO = '70163299';
const TOLERANCIA = 1.5;

const montoValido = montoEsperado > 0 && Math.abs(montoDetectado - montoEsperado) <= TOLERANCIA;
const nombreValido = nombreDetectado.includes(NOMBRE_ESPERADO) || NOMBRE_ESPERADO.includes(nombreDetectado.split(' ')[0]);
const celularValido = celularDetectado === CELULAR_ESPERADO;

const datosCorrectos = montoValido && nombreValido && celularValido;

const razonFallo = [];
if (!montoValido) razonFallo.push('monto detectado: ' + montoDetectado + ', esperado: ' + montoEsperado);
if (!nombreValido) razonFallo.push('nombre detectado: "' + extractedData.nombreDestinatario + '"');
if (!celularValido) razonFallo.push('celular detectado: "' + extractedData.celularDestino + '"');

return [{
  json: {
    datosCorrectos,
    montoDetectado,
    montoEsperado,
    montoValido,
    nombreDetectado: extractedData.nombreDestinatario,
    nombreValido,
    celularDetectado: extractedData.celularDestino,
    celularValido,
    mensaje: datosCorrectos
      ? 'Comprobante verificado correctamente'
      : 'Datos no coinciden: ' + razonFallo.join('; ')
  }
}];
